import { FC, ReactNode, useEffect, useMemo, useState } from 'react'
import {
  Tag,
  Badge,
  Button,
  Checkbox,
  Input,
  Form,
  Grid,
  Modal,
  Message,
} from '@arco-design/web-react'
import {
  IconFile,
  IconClose,
  IconSave,
  IconUpload,
  IconRefresh,
} from '@arco-design/web-react/icon'
import { useTranslation } from 'react-i18next'
import _, { divide } from 'lodash'
import SignatureImageGenerator from './components/SignatureImage'
import { SignatureChangePayload } from './components/SignatureImage'
import { getContractorDetail, contractorSubmit } from '@/service'
import { useRequest } from 'ahooks'
import { useSearchParams } from 'react-router-dom'
import UploadFile from './components/UploadFile'
import {
  UsePermitToWorkCategoryText,
  UsePermitToWorkTypeText,
} from '@/constants/permitToWork.ts'

import './index.less'

const FormItem = Form.Item
const { Row, Col } = Grid
const TextArea = Input.TextArea

const pledgeItems = [
  'Tool box talk to be conducted to all staff',
  'Emergency response, safety instruction and assembly point staff education',
  'Placement of warning signs indicating ongoing work or closure with caution tape',
  'Ensure the workplace is clean and safe during and after project delivery',
  'Authorisation and Acceptance',
]

const pledgeTranslationKeys = [
  'contractorPortal:pledge.item0',
  'contractorPortal:pledge.item1',
  'contractorPortal:pledge.item2',
  'contractorPortal:pledge.item3',
  'contractorPortal:pledge.item4',
] as const

const isAllPledgeChecked = (checkedValues: string[] = []) => {
  if (!Array.isArray(checkedValues)) return false
  return pledgeItems.every((item) => checkedValues.includes(item))
}

const ContractorPortal = () => {
  const { t } = useTranslation(['common', 'contractorPortal'])
  const [form] = Form.useForm()
  const [submitModalVisible, setSubmitModalVisible] = useState(false)
  const [methodStatementFiles, setMethodStatementFiles] = useState<any>([])
  const [riskStatementFiles, setRiskStatementFiles] = useState<any>([])
  const [controlsFiles, setControlsFiles] = useState<any>([])
  const [isPledgeFullyChecked, setIsPledgeFullyChecked] = useState(false)
  const [searchParams] = useSearchParams()
  const urlToken = searchParams.get('token')
  ///签名
  const [name, setName] = useState('')
  const [isAutoGenerateEnabled, setIsAutoGenerateEnabled] = useState(true)
  const [clearSignal, setClearSignal] = useState(0)
  const [signatureFileFromChild, setSignatureFileFromChild] =
    useState<File | null>(null)
  const [signaturePayload, setSignaturePayload] =
    useState<SignatureChangePayload>({
      blob: null,
      file: null,
      url: '',
    })
  const [onUploadSuccess, SetOnUploadSuccess] = useState<any>()

  //
  const [dataInfo, setDataInfo] = useState<any>()
  const isCategoryTwo = dataInfo?.category == 2

  const permitToWorkTypeText = UsePermitToWorkTypeText()
  const permitToWorkCategoryText = UsePermitToWorkCategoryText()

  const { run: runContractorDetail, loading: getContractorDetailLoading } =
    useRequest(getContractorDetail, {
      manual: true,
      onSuccess: (res: any) => {
        setDataInfo(res)
      },
    })

  useEffect(() => {
    if (urlToken) {
      runContractorDetail({ token: urlToken })
    }
  }, [urlToken])

  const { run: runContractorSubmit, loading: contractorSubmitLoading } =
    useRequest(contractorSubmit, {
      manual: true,
      onSuccess: (res: any) => {
        Message.success(t('common:message.submitSuccessfully'))
        setSubmitModalVisible(false)
      },
    })

  const handleSubmit = () => {
    // Keep as placeholder, next step can integrate API submit.
    const pledgeChecked = form.getFieldValue('pledgeChecked') || []
    if (!isAllPledgeChecked(pledgeChecked)) return
    if (isCategoryTwo && !hasUploadedAllCategoryTwoAttachments) return

    form.validate().then(() => {
      const data = form.getFieldsValue()
      const params = {
        ...data,
        methodList: methodStatementFiles,
        riskList: riskStatementFiles,
        controlList: controlsFiles,
        contractorSign: onUploadSuccess,
        token: urlToken,
      }
      runContractorSubmit(params)
    })
  }

  const handleOpenSubmitModal = () => {
    if (isSubmitDisabled) return
    setSubmitModalVisible(true)
  }

  const handleCancelSubmitModal = () => {
    setSubmitModalVisible(false)
  }

  const handleConfirmSubmit = () => {
    setSubmitModalVisible(false)
    handleSubmit()
  }

  const handleMethodStatementUploadSuccess = (_: any, file: File) => {
    setMethodStatementFiles((prev) => [...prev, _])
  }

  const handleRiskStatementUploadSuccess = (_: any, file: File) => {
    setRiskStatementFiles((prev) => [...prev, _])
  }

  const handleControlsUploadSuccess = (_: any, file: File) => {
    setControlsFiles((prev) => [...prev, _])
  }

  const getFileDisplayName = (file: any) => {
    return file?.name || file?.fileName || file?.attachName || 'Unknown File'
  }

  const getFileStatus = (file: any) => {
    return file?.status || 'default'
  }

  const deleteFileFromList = (
    setList: React.Dispatch<React.SetStateAction<any[]>>,
    index: number,
  ) => {
    setList((prev) => {
      const deletedFile = prev[index]
      return prev.filter((_: any, i: number) => i !== index)
    })
  }
  const hasUploadedAllCategoryTwoAttachments =
    methodStatementFiles.length > 0 &&
    riskStatementFiles.length > 0 &&
    controlsFiles.length > 0
  const isSubmitDisabled =
    !isPledgeFullyChecked ||
    (isCategoryTwo && !hasUploadedAllCategoryTwoAttachments)
  const spanNum = isCategoryTwo ? 8 : 12
  return (
    <div className='contractor-portal-page'>
      <div className='contractor-portal-card'>
        <div className='permit-code'>
          {t('contractorPortal:permitCode')} {dataInfo?.permitCode}
        </div>
        <div className='main-title'>{t('contractorPortal:mainTitle')}</div>
        <p className='subtitle'>{t('contractorPortal:subtitle')}</p>

        <Form
          form={form}
          layout='vertical'
          className='contractor-portal-form'
          onSubmit={handleSubmit}
        >
          <section>
            <div className='permit-details-box'>
              <div className='section-title'>
                {t('contractorPortal:section.permitDetails')}
              </div>
              <Row className='detail-grid' gutter={[22, 10]}>
                <Col span={spanNum}>
                  <div className='label'>
                    {t('contractorPortal:label.permitCategory')}
                  </div>
                  <div className='value'>
                    {permitToWorkCategoryText[dataInfo?.category]}
                  </div>
                </Col>
                {dataInfo?.category == 2 && (
                  <Col span={8}>
                    <div className='label'>
                      {t('contractorPortal:label.permitType')}
                    </div>
                    <div className='value'>
                      {permitToWorkTypeText[dataInfo?.permitType]}
                    </div>
                  </Col>
                )}

                <Col span={spanNum}>
                  <div className='label'>
                    {t('contractorPortal:label.concernedDepartment')}
                  </div>
                  <div className='value'>{dataInfo?.department.orgName}</div>
                </Col>
                <Col span={spanNum}>
                  <div className='label'>
                    {t('contractorPortal:label.validFrom')}
                  </div>
                  <div className='value'>{dataInfo?.startTime}</div>
                </Col>
                <Col span={spanNum}>
                  <div className='label'>
                    {t('contractorPortal:label.validTo')}
                  </div>
                  <div className='value'>{dataInfo?.endTime}</div>
                </Col>
                <Col span={24}>
                  <div className='label'>
                    {t('contractorPortal:label.locationAtWork')}
                  </div>
                  <div className='value'>{dataInfo?.location}</div>
                </Col>
              </Row>
            </div>
          </section>

          {dataInfo?.category == 2 && (
            <>
              <section>
                <div className='section-title'>
                  {t('contractorPortal:section.contractorHsOfficer')}
                </div>
                <FormItem
                  className='form-row'
                  field='assignedContractorOfficerName'
                  label={t(
                    'contractorPortal:label.assigneeContractorHsOfficerName',
                  )}
                  rules={[
                    {
                      required: true,
                      message: t(
                        'contractorPortal:validation.pleaseEnterAssigneeOfficerName',
                      ),
                    },
                  ]}
                >
                  <Input
                    style={{ width: '50%' }}
                    placeholder={t('common:pleaseEnter')}
                  />
                </FormItem>
              </section>

              <section>
                <h2 className='section-title'>
                  {t('contractorPortal:section.documentsSubmitted')}
                </h2>
                <div className='docs-list'>
                  {/* 第一个 */}
                  <FormItem field={'method'}></FormItem>
                  <div className='doc-row'>
                    <div className='doc-content'>
                      <div className='doc-title'>
                        {t('contractorPortal:label.methodStatement')}
                      </div>
                      <div className='doc-desc'>
                        {t('contractorPortal:doc.methodStatementDesc')}
                      </div>
                      <div className='file-tags'>
                        {methodStatementFiles.map((file, index) => (
                          <span
                            className={`file-tag file-tag-${getFileStatus(file)}`}
                            key={`${getFileDisplayName(file)}-${index}`}
                          >
                            <span className='file-tag-icon'>
                              <IconFile />
                            </span>
                            <span>{getFileDisplayName(file)}</span>
                            <span
                              className='file-tag-close'
                              onClick={() =>
                                deleteFileFromList(
                                  setMethodStatementFiles,
                                  index,
                                )
                              }
                            >
                              <IconClose />
                            </span>
                          </span>
                        ))}
                      </div>
                    </div>
                    <UploadFile
                      className='attach-btn'
                      accept='.pdf,.png,.jpg,.jpeg'
                      onUploadSuccess={handleMethodStatementUploadSuccess}
                      urlToken={urlToken}
                    />
                  </div>
                  {/* 第二个 */}
                  <div className='doc-row'>
                    <div className='doc-content'>
                      <div className='doc-title'>
                        {t('contractorPortal:label.riskStatement')}
                      </div>
                      <div className='doc-desc'>
                        {t('contractorPortal:doc.riskStatementDesc')}
                      </div>
                      <div className='file-tags'>
                        {riskStatementFiles.map((file, index) => (
                          <span
                            className={`file-tag file-tag-${getFileStatus(file)}`}
                            key={`${getFileDisplayName(file)}-${index}`}
                          >
                            <span className='file-tag-icon'>
                              <IconFile />
                            </span>
                            <span>{getFileDisplayName(file)}</span>
                            <span
                              className='file-tag-close'
                              onClick={() =>
                                deleteFileFromList(setRiskStatementFiles, index)
                              }
                            >
                              <IconClose />
                            </span>
                          </span>
                        ))}
                      </div>
                    </div>
                    <UploadFile
                      className='attach-btn'
                      accept='.pdf,.png,.jpg,.jpeg'
                      onUploadSuccess={handleRiskStatementUploadSuccess}
                      urlToken={urlToken}
                    />
                  </div>
                  {/* 第三个 */}
                  <div className='doc-row'>
                    <div className='doc-content'>
                      <div className='doc-title'>
                        {t('contractorPortal:label.controls')}
                      </div>
                      <div className='doc-desc'>
                        {t('contractorPortal:doc.controlsDesc')}
                      </div>
                      <div className='file-tags'>
                        {controlsFiles.map((file, index) => (
                          <span
                            className={`file-tag file-tag-${getFileStatus(file)}`}
                            key={`${getFileDisplayName(file)}-${index}`}
                          >
                            <span className='file-tag-icon'>
                              <IconFile />
                            </span>
                            <span>{getFileDisplayName(file)}</span>
                            <span
                              className='file-tag-close'
                              onClick={() =>
                                deleteFileFromList(setControlsFiles, index)
                              }
                            >
                              <IconClose />
                            </span>
                          </span>
                        ))}
                      </div>
                    </div>
                    <UploadFile
                      className='attach-btn'
                      accept='.pdf,.png,.jpg,.jpeg'
                      onUploadSuccess={handleControlsUploadSuccess}
                      urlToken={urlToken}
                    />
                  </div>
                </div>
              </section>
            </>
          )}

          <section>
            <h2 className='section-title'>
              {t('contractorPortal:section.moreInformation')}
            </h2>
            <div className='more-info-list'>
              <FormItem
                className='form-row'
                field='contractorEquipmentAr'
                label={t('contractorPortal:label.equipmentRequiredAr')}
                rules={[
                  {
                    required: true,
                    message: t(
                      'contractorPortal:validation.pleaseEnterEquipmentRequiredAr',
                    ),
                  },
                ]}
              >
                <TextArea
                  className={`rtl-input`}
                  maxLength={500}
                  showWordLimit
                  placeholder={t('common:pleaseEnter')}
                />
              </FormItem>

              <FormItem
                className='form-row'
                field='contractorEquipment'
                label={t('contractorPortal:label.equipmentRequiredEn')}
              >
                <TextArea
                  maxLength={500}
                  showWordLimit
                  placeholder={t('common:pleaseEnter')}
                />
              </FormItem>

              <FormItem
                className='form-row'
                field='contractorPpeAr'
                label={t('contractorPortal:label.ppeRequiredAr')}
                rules={[
                  {
                    required: true,
                    message: t(
                      'contractorPortal:validation.pleaseEnterPpeRequiredAr',
                    ),
                  },
                ]}
              >
                <TextArea
                  className={`rtl-input`}
                  maxLength={500}
                  showWordLimit
                  placeholder={t('common:pleaseEnter')}
                />
              </FormItem>

              <FormItem
                className='form-row'
                field='contractorPpe'
                label={t('contractorPortal:label.ppeRequiredEn')}
              >
                <TextArea
                  maxLength={500}
                  showWordLimit
                  placeholder={t('common:pleaseEnter')}
                />
              </FormItem>
            </div>
          </section>

          <section>
            <h2 className='section-title'>
              {t('contractorPortal:section.pledge')}
            </h2>
            <FormItem
              className='pledge-form-row'
              field='pledgeChecked'
              rules={[
                {
                  type: 'array',
                  required: true,
                  min: 1,
                  message: t('contractorPortal:validation.pleaseSelectPledge'),
                },
              ]}
            >
              <Checkbox.Group
                className='pledge-list'
                onChange={(values) =>
                  setIsPledgeFullyChecked(
                    isAllPledgeChecked(values as string[]),
                  )
                }
              >
                {pledgeItems.map((item, index) => (
                  <Checkbox
                    key={item}
                    value={item}
                    className='pledge-list-item'
                  >
                    {t(pledgeTranslationKeys[index])}
                  </Checkbox>
                ))}
                <div className='acceptance'>
                  {t('contractorPortal:pledge.acceptance')}
                </div>
              </Checkbox.Group>
            </FormItem>
            <p className='authorization-desc'></p>
          </section>

          <section>
            <div className='section-title'>
              {t('contractorPortal:section.contractorHsOfficer')}
            </div>
            <Row className='signature-area' gutter={10}>
              <Col span={12}>
                <div className='left-form'>
                  <FormItem
                    className='form-row'
                    field='contractorOfficerName'
                    label={t('contractorPortal:label.name')}
                    rules={[
                      {
                        required: true,
                        message: t(
                          'contractorPortal:validation.pleaseEnterName',
                        ),
                      },
                    ]}
                  >
                    <Input
                      onChange={(value) => setName(value)}
                      placeholder={t('common:pleaseEnter')}
                    />
                  </FormItem>
                  <FormItem
                    className='form-row'
                    field='contractorOfficerDesignation'
                    label={t('contractorPortal:label.designation')}
                    rules={[
                      {
                        required: true,
                        message: t(
                          'contractorPortal:validation.pleaseEnterDesignation',
                        ),
                      },
                    ]}
                  >
                    <Input placeholder={t('common:pleaseEnter')} />
                  </FormItem>
                </div>
              </Col>
              <Col span={12}>
                <div className='signature-form'>
                  <div>
                    <FormItem
                      className='form-row'
                      field='contractorDesignation'
                      label={t('contractorPortal:label.designation')}
                      rules={[
                        {
                          required: true,
                          message: t(
                            'contractorPortal:validation.pleaseEnterDesignation',
                          ),
                        },
                      ]}
                    ></FormItem>
                  </div>

                  <div
                    className='signature-iconRefresh'
                    onClick={() => {
                      setName('')
                      setClearSignal((prev) => prev + 1)
                      form.setFieldValue('contractorOfficerName', '')
                    }}
                  >
                    <div>
                      <IconRefresh />
                    </div>
                    <div>{t('common:btn.clear')}</div>
                  </div>
                </div>

                <div className='signature-card'>
                  <SignatureImageGenerator
                    name={name}
                    enabled={isAutoGenerateEnabled}
                    autoUpload={false}
                    clearSignal={clearSignal}
                    onSignatureChange={setSignaturePayload}
                    onFileChange={setSignatureFileFromChild}
                    onUploadSuccess={SetOnUploadSuccess}
                    urlToken={urlToken}
                  />
                </div>
              </Col>
            </Row>
          </section>
          <div className='action-group'>
            <Button className='save-btn' icon={<IconSave />}>
              {t('common:btn.save')}
            </Button>
            <Button
              className='submit-btn'
              type='primary'
              icon={<IconUpload />}
              disabled={isSubmitDisabled}
              // loading={contractorSubmitLoading}
              onClick={handleOpenSubmitModal}
            >
              {t('common:btn.submit')}
            </Button>
          </div>
        </Form>
      </div>

      <Modal
        visible={submitModalVisible}
        title={null}
        closable
        className='submit-confirm-modal'
        onCancel={handleCancelSubmitModal}
        onOk={() => handleSubmit()}
        maskClosable={false}
        style={{ width: '336px', height: '150px' }}
      >
        <div className='submit-confirm-content'>
          <div className='submit-confirm-header'>
            <div className='submit-confirm-icon'>i</div>
            <div className='submit-confirm-title'>
              {t('contractorPortal:modal.submitConfirmTitle')}
            </div>
          </div>
          <div className='submit-confirm-desc'>
            {t('contractorPortal:modal.submitConfirmDesc')}
          </div>
        </div>
      </Modal>
    </div>
  )
}
export default ContractorPortal

import { FC, ReactNode, useEffect, useMemo, useState } from 'react'
import {
  Tag,
  Badge,
  Button,
  Checkbox,
  Input,
  Form,
  Grid,
  Modal,
  Message,
} from '@arco-design/web-react'
import {
  IconFile,
  IconClose,
  IconSave,
  IconUpload,
} from '@arco-design/web-react/icon'
import { useTranslation } from 'react-i18next'
import _, { divide } from 'lodash'
import SignatureImageGenerator from './components/SignatureImage'
import { SignatureChangePayload } from './components/SignatureImage'
import { getContractorDetail, contractorSubmit } from '@/service'
import { useRequest } from 'ahooks'
import { useSearchParams } from 'react-router-dom'
import UploadFile from './components/UploadFile'
import {
  UsePermitToWorkCategoryText,
  UsePermitToWorkTypeText,
} from '@/constants/permitToWork.ts'

import './index.less'

const FormItem = Form.Item
const { Row, Col } = Grid
const TextArea = Input.TextArea

const pledgeItems = [
  'Tool box talk to be conducted to all staff',
  'Emergency response, safety instruction and assembly point staff education',
  'Placement of warning signs indicating ongoing work or closure with caution tape',
  'Ensure the workplace is clean and safe during and after project delivery',
  'Authorisation and Acceptance',
]

const pledgeTranslationKeys = [
  'contractorPortal:pledge.item0',
  'contractorPortal:pledge.item1',
  'contractorPortal:pledge.item2',
  'contractorPortal:pledge.item3',
  'contractorPortal:pledge.item4',
] as const

const isAllPledgeChecked = (checkedValues: string[] = []) => {
  if (!Array.isArray(checkedValues)) return false
  return pledgeItems.every((item) => checkedValues.includes(item))
}

const ContractorPortal = () => {
  const { t } = useTranslation(['common', 'contractorPortal'])
  const [form] = Form.useForm()
  const [submitModalVisible, setSubmitModalVisible] = useState(false)
  const [methodStatementFiles, setMethodStatementFiles] = useState<any>([])
  const [riskStatementFiles, setRiskStatementFiles] = useState<any>([])
  const [controlsFiles, setControlsFiles] = useState<any>([])
  const [isPledgeFullyChecked, setIsPledgeFullyChecked] = useState(false)
  const [searchParams] = useSearchParams()
  const urlToken = searchParams.get('token')
  ///签名
  const [name, setName] = useState('')
  const [isAutoGenerateEnabled, setIsAutoGenerateEnabled] = useState(true)
  const [clearSignal, setClearSignal] = useState(0)
  const [signatureFileFromChild, setSignatureFileFromChild] =
    useState<File | null>(null)
  const [signaturePayload, setSignaturePayload] =
    useState<SignatureChangePayload>({
      blob: null,
      file: null,
      url: '',
    })
  const [onUploadSuccess, SetOnUploadSuccess] = useState<any>()

  //
  const [dataInfo, setDataInfo] = useState<any>()
  const isCategoryTwo = dataInfo?.category == 2

  const permitToWorkTypeText = UsePermitToWorkTypeText()
  const permitToWorkCategoryText = UsePermitToWorkCategoryText()

  const { run: runContractorDetail, loading: getContractorDetailLoading } =
    useRequest(getContractorDetail, {
      manual: true,
      onSuccess: (res: any) => {
        setDataInfo(res)
      },
    })

  useEffect(() => {
    if (urlToken) {
      runContractorDetail({ token: urlToken })
    }
  }, [urlToken])

  const { run: runContractorSubmit, loading: contractorSubmitLoading } =
    useRequest(contractorSubmit, {
      manual: true,
      onSuccess: (res: any) => {
        Message.success(t('common:message.submitSuccessfully'))
        setSubmitModalVisible(false)
      },
    })

  const handleSubmit = () => {
    // Keep as placeholder, next step can integrate API submit.
    const pledgeChecked = form.getFieldValue('pledgeChecked') || []
    if (!isAllPledgeChecked(pledgeChecked)) return
    if (isCategoryTwo && !hasUploadedAllCategoryTwoAttachments) return

    form.validate().then(() => {
      const data = form.getFieldsValue()
      const params = {
        ...data,
        methodList: methodStatementFiles,
        riskList: riskStatementFiles,
        controlList: controlsFiles,
        contractorSign: onUploadSuccess,
        token: urlToken,
      }
      runContractorSubmit(params)
    })
  }

  const handleOpenSubmitModal = () => {
    if (isSubmitDisabled) return
    setSubmitModalVisible(true)
  }

  const handleCancelSubmitModal = () => {
    setSubmitModalVisible(false)
  }

  const handleConfirmSubmit = () => {
    setSubmitModalVisible(false)
    handleSubmit()
  }

  const handleMethodStatementUploadSuccess = (_: any, file: File) => {
    setMethodStatementFiles((prev) => [...prev, _])
  }

  const handleRiskStatementUploadSuccess = (_: any, file: File) => {
    setRiskStatementFiles((prev) => [...prev, _])
  }

  const handleControlsUploadSuccess = (_: any, file: File) => {
    setControlsFiles((prev) => [...prev, _])
  }

  const getFileDisplayName = (file: any) => {
    return file?.name || file?.fileName || file?.attachName || 'Unknown File'
  }

  const getFileStatus = (file: any) => {
    return file?.status || 'default'
  }

  const deleteFileFromList = (
    setList: React.Dispatch<React.SetStateAction<any[]>>,
    index: number,
  ) => {
    setList((prev) => {
      const deletedFile = prev[index]
      return prev.filter((_: any, i: number) => i !== index)
    })
  }
  const hasUploadedAllCategoryTwoAttachments =
    methodStatementFiles.length > 0 &&
    riskStatementFiles.length > 0 &&
    controlsFiles.length > 0
  const isSubmitDisabled =
    !isPledgeFullyChecked ||
    (isCategoryTwo && !hasUploadedAllCategoryTwoAttachments)
  const spanNum = isCategoryTwo ? 8 : 12
  return (
    <div className='contractor-portal-page'>
      <div className='contractor-portal-card'>
        <div className='permit-code'>{t('contractorPortal:permitCode')} {dataInfo?.permitCode}</div>
        <div className='main-title'>{t('contractorPortal:mainTitle')}</div>
        <p className='subtitle'>{t('contractorPortal:subtitle')}</p>

        <Form
          form={form}
          layout='vertical'
          className='contractor-portal-form'
          onSubmit={handleSubmit}
        >
          <section>
            <div className='permit-details-box'>
              <div className='section-title'>{t('contractorPortal:section.permitDetails')}</div>
              <Row className='detail-grid' gutter={[22, 10]}>
                <Col span={spanNum}>
                  <div className='label'>{t('contractorPortal:label.permitCategory')}</div>
                  <div className='value'>
                    {permitToWorkCategoryText[dataInfo?.category]}
                  </div>
                </Col>
                {dataInfo?.category == 2 && (
                  <Col span={8}>
                    <div className='label'>{t('contractorPortal:label.permitType')}</div>
                    <div className='value'>
                      {permitToWorkTypeText[dataInfo?.permitType]}
                    </div>
                  </Col>
                )}

                <Col span={spanNum}>
                  <div className='label'>{t('contractorPortal:label.concernedDepartment')}</div>
                  <div className='value'>{dataInfo?.department.orgName}</div>
                </Col>
                <Col span={spanNum}>
                  <div className='label'>{t('contractorPortal:label.validFrom')}</div>
                  <div className='value'>{dataInfo?.startTime}</div>
                </Col>
                <Col span={spanNum}>
                  <div className='label'>{t('contractorPortal:label.validTo')}</div>
                  <div className='value'>{dataInfo?.endTime}</div>
                </Col>
                <Col span={24}>
                  <div className='label'>{t('contractorPortal:label.locationAtWork')}</div>
                  <div className='value'>{dataInfo?.location}</div>
                </Col>
              </Row>
            </div>
          </section>

          {dataInfo?.category == 2 && (
            <>
              <section>
                <div className='section-title'>{t('contractorPortal:section.contractorHsOfficer')}</div>
                <FormItem
                  className='form-row'
                  field='assignedContractorOfficerName'
                  label={t('contractorPortal:label.assigneeContractorHsOfficerName')}
                  rules={[
                    {
                      required: true,
                      message: t('contractorPortal:validation.pleaseEnterAssigneeOfficerName'),
                    },
                  ]}
                >
                  <Input
                    style={{ width: '50%' }}
                    placeholder={t('common:pleaseEnter')}
                  />
                </FormItem>
              </section>

              <section>
                <h2 className='section-title'>
                  {t('contractorPortal:section.documentsSubmitted')}
                </h2>
                <div className='docs-list'>
                  {/* 第一个 */}
                  <FormItem field={'method'}></FormItem>
                  <div className='doc-row'>
                    <div className='doc-content'>
                      <div className='doc-title'>{t('contractorPortal:label.methodStatement')}</div>
                      <div className='doc-desc'>
                        {t('contractorPortal:doc.methodStatementDesc')}
                      </div>
                      <div className='file-tags'>
                        {methodStatementFiles.map((file, index) => (
                          <span
                            className={`file-tag file-tag-${getFileStatus(file)}`}
                            key={`${getFileDisplayName(file)}-${index}`}
                          >
                            <span className='file-tag-icon'>
                              <IconFile />
                            </span>
                            <span>{getFileDisplayName(file)}</span>
                            <span
                              className='file-tag-close'
                              onClick={() =>
                                deleteFileFromList(
                                  setMethodStatementFiles,
                                  index,
                                )
                              }
                            >
                              <IconClose />
                            </span>
                          </span>
                        ))}
                      </div>
                    </div>
                    <UploadFile
                      className='attach-btn'
                      accept='.pdf,.png,.jpg,.jpeg'
                      onUploadSuccess={handleMethodStatementUploadSuccess}
                      urlToken={urlToken}
                    />
                  </div>
                  {/* 第二个 */}
                  <div className='doc-row'>
                    <div className='doc-content'>
                      <div className='doc-title'>{t('contractorPortal:label.riskStatement')}</div>
                      <div className='doc-desc'>
                        {t('contractorPortal:doc.riskStatementDesc')}
                      </div>
                      <div className='file-tags'>
                        {riskStatementFiles.map((file, index) => (
                          <span
                            className={`file-tag file-tag-${getFileStatus(file)}`}
                            key={`${getFileDisplayName(file)}-${index}`}
                          >
                            <span className='file-tag-icon'>
                              <IconFile />
                            </span>
                            <span>{getFileDisplayName(file)}</span>
                            <span
                              className='file-tag-close'
                              onClick={() =>
                                deleteFileFromList(setRiskStatementFiles, index)
                              }
                            >
                              <IconClose />
                            </span>
                          </span>
                        ))}
                      </div>
                    </div>
                    <UploadFile
                      className='attach-btn'
                      accept='.pdf,.png,.jpg,.jpeg'
                      onUploadSuccess={handleRiskStatementUploadSuccess}
                      urlToken={urlToken}
                    />
                  </div>
                  {/* 第三个 */}
                  <div className='doc-row'>
                    <div className='doc-content'>
                      <div className='doc-title'>{t('contractorPortal:label.controls')}</div>
                      <div className='doc-desc'>
                        {t('contractorPortal:doc.controlsDesc')}
                      </div>
                      <div className='file-tags'>
                        {controlsFiles.map((file, index) => (
                          <span
                            className={`file-tag file-tag-${getFileStatus(file)}`}
                            key={`${getFileDisplayName(file)}-${index}`}
                          >
                            <span className='file-tag-icon'>
                              <IconFile />
                            </span>
                            <span>{getFileDisplayName(file)}</span>
                            <span
                              className='file-tag-close'
                              onClick={() =>
                                deleteFileFromList(setControlsFiles, index)
                              }
                            >
                              <IconClose />
                            </span>
                          </span>
                        ))}
                      </div>
                    </div>
                    <UploadFile
                      className='attach-btn'
                      accept='.pdf,.png,.jpg,.jpeg'
                      onUploadSuccess={handleControlsUploadSuccess}
                      urlToken={urlToken}
                    />
                  </div>
                </div>
              </section>
            </>
          )}

          <section>
            <h2 className='section-title'>{t('contractorPortal:section.moreInformation')}</h2>
            <div className='more-info-list'>
              <FormItem
                className='form-row'
                field='contractorEquipmentAr'
                label={t('contractorPortal:label.equipmentRequiredAr')}
                rules={[
                  {
                    required: true,
                    message: t('contractorPortal:validation.pleaseEnterEquipmentRequiredAr'),
                  },
                ]}
              >
                <TextArea
                  maxLength={500}
                  showWordLimit
                  placeholder={t('common:pleaseEnter')}
                />
              </FormItem>

              <FormItem
                className='form-row'
                field='contractorEquipment'
                label={t('contractorPortal:label.equipmentRequiredEn')}
              >
                <TextArea
                  maxLength={500}
                  showWordLimit
                  placeholder={t('common:pleaseEnter')}
                />
              </FormItem>

              <FormItem
                className='form-row'
                field='contractorPpeAr'
                label={t('contractorPortal:label.ppeRequiredAr')}
                rules={[
                  {
                    required: true,
                    message: t('contractorPortal:validation.pleaseEnterPpeRequiredAr'),
                  },
                ]}
              >
                <TextArea
                  maxLength={500}
                  showWordLimit
                  placeholder={t('common:pleaseEnter')}
                />
              </FormItem>

              <FormItem
                className='form-row'
                field='contractorPpe'
                label={t('contractorPortal:label.ppeRequiredEn')}
              >
                <TextArea
                  maxLength={500}
                  showWordLimit
                  placeholder={t('common:pleaseEnter')}
                />
              </FormItem>
            </div>
          </section>

          <section>
            <h2 className='section-title'>{t('contractorPortal:section.pledge')}</h2>
            <FormItem
              className='pledge-form-row'
              field='pledgeChecked'
              rules={[
                {
                  type: 'array',
                  required: true,
                  min: 1,
                  message: t('contractorPortal:validation.pleaseSelectPledge'),
                },
              ]}
            >
              <Checkbox.Group
                className='pledge-list'
                onChange={(values) =>
                  setIsPledgeFullyChecked(
                    isAllPledgeChecked(values as string[]),
                  )
                }
              >
                {pledgeItems.map((item, index) => (
                  <Checkbox key={item} value={item}>
                    {t(pledgeTranslationKeys[index])}
                  </Checkbox>
                ))}
                <div className='acceptance'>
                  {t('contractorPortal:pledge.acceptance')}
                </div>
              </Checkbox.Group>
            </FormItem>
            <p className='authorization-desc'></p>
          </section>

          <section>
            <div className='section-title'>{t('contractorPortal:section.contractorHsOfficer')}</div>
            <Row className='signature-area' gutter={10}>
              <Col span={12}>
                <div className='left-form'>
                  <FormItem
                    className='form-row'
                    field='contractorOfficerName'
                    label={t('contractorPortal:label.name')}
                    rules={[{ required: true, message: t('contractorPortal:validation.pleaseEnterName') }]}
                  >
                    <Input
                      onChange={(value) => setName(value)}
                      placeholder={t('common:pleaseEnter')}
                    />
                  </FormItem>
                  <FormItem
                    className='form-row'
                    field='contractorOfficerDesignation'
                    label={t('contractorPortal:label.designation')}
                    rules={[
                      { required: true, message: t('contractorPortal:validation.pleaseEnterDesignation') },
                    ]}
                  >
                    <Input placeholder={t('common:pleaseEnter')} />
                  </FormItem>
                </div>
              </Col>
              <Col span={12}>
                <FormItem
                  className='form-row'
                  field='contractorDesignation'
                  label={t('contractorPortal:label.designation')}
                  rules={[
                    { required: true, message: t('contractorPortal:validation.pleaseEnterDesignation') },
                  ]}
                ></FormItem>
                <div className='signature-card'>
                  {/* <div className='signature-placeholder'>A. Ahmed</div> */}
                  <SignatureImageGenerator
                    name={name}
                    enabled={isAutoGenerateEnabled}
                    autoUpload={false}
                    clearSignal={clearSignal}
                    onSignatureChange={setSignaturePayload}
                    onFileChange={setSignatureFileFromChild}
                    onUploadSuccess={SetOnUploadSuccess}
                    urlToken={urlToken}
                  />
                </div>
              </Col>
            </Row>
          </section>
          <div className='action-group'>
            <Button className='save-btn' icon={<IconSave />}>
              {t('common:btn.save')}
            </Button>
            <Button
              className='submit-btn'
              type='primary'
              icon={<IconUpload />}
              disabled={isSubmitDisabled}
              // loading={contractorSubmitLoading}
              onClick={handleOpenSubmitModal}
            >
              {t('common:btn.submit')}
            </Button>
          </div>
        </Form>
      </div>

      <Modal
        visible={submitModalVisible}
        title={null}
        closable
        className='submit-confirm-modal'
        onCancel={handleCancelSubmitModal}
        onOk={() => handleSubmit()}
        maskClosable={false}
        style={{ width: '336px', height: '150px' }}
      >
        <div className='submit-confirm-content'>
          <div className='submit-confirm-header'>
            <div className='submit-confirm-icon'>i</div>
            <div className='submit-confirm-title'>{t('contractorPortal:modal.submitConfirmTitle')}</div>
          </div>
          <div className='submit-confirm-desc'>{t('contractorPortal:modal.submitConfirmDesc')}</div>
        </div>
      </Modal>
    </div>
  )
}
export default ContractorPortal

