import { useCallback, useEffect, useRef, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { File_UPLOAD_TYPE } from '@common/constants/uploadTypes'
import { openapiUploadFile as uploadFile } from '@/service'
import './index.less'

const SIGNATURE_FONT_FAMILY =
  "'Mr De Haviland', 'Brush Script MT', 'Lucida Handwriting', cursive"
const SIGNATURE_FONT_SIZE = 64
const SIGNATURE_WIDTH = 356
const SIGNATURE_HEIGHT = 80
const SIGNATURE_SCALE = 2
const SIGNATURE_UPLOAD_DEBOUNCE_MS = 800

export interface SignatureChangePayload {
  blob: Blob | null
  file: File | null
  url: string
  uploadedData?: any
  uploading?: boolean
  uploadError?: unknown
}

interface SignatureImageGeneratorProps {
  name: string
  enabled: boolean
  autoUpload?: boolean
  clearSignal: number
  fileUploadType?: number
  onSignatureChange?: (payload: SignatureChangePayload) => void
  onFileChange?: (file: File | null) => void
  onUploadSuccess?: (data: any) => void
  urlToken?: any
}

const SignatureImageGenerator = ({
  name,
  enabled,
  autoUpload = true,
  clearSignal,
  fileUploadType = 1,
  onSignatureChange,
  onFileChange,
  onUploadSuccess,
  urlToken,
}: SignatureImageGeneratorProps) => {
  const { t } = useTranslation('permitToWork')
  // 当前生成出的签名图片数据（用于预览与向外抛出）。
  const [signatureBlob, setSignatureBlob] = useState<Blob | null>(null)
  const [signatureFile, setSignatureFile] = useState<File | null>(null)
  const [signatureUrl, setSignatureUrl] = useState('')
  // 字体可用后再绘制，避免首次渲染命中回退字体。
  const [fontReady, setFontReady] = useState(false)
  const objectUrlRef = useRef<string>('')
  // 用于忽略过期异步任务（快速输入时旧任务结果不覆盖新任务）。
  const generateTaskIdRef = useRef(0)
  const latestGeneratedNameRef = useRef('')
  const uploadDebounceTimerRef = useRef<number | null>(null)
  const uploadAbortControllerRef = useRef<AbortController | null>(null)
  const lastUploadedSignatureKeyRef = useRef('')

  /**
   * 确保签名字体已加载。
   */
  const ensureSignatureFontLoaded = useCallback(async () => {
    if (!('fonts' in document)) {
      setFontReady(true)
      return
    }

    try {
      const fontSpec = `400 ${SIGNATURE_FONT_SIZE}px "Mr De Haviland"`
      await document.fonts.load(fontSpec)
      await document.fonts.ready
      setFontReady(document.fonts.check(fontSpec))
    } catch {
      setFontReady(true)
    }
  }, [])

  /**
   * 清空当前签名数据并释放 objectURL。
   * notifyParent=true 时同步通知外部“签名已清空”。
   */
  const clearSignatureData = useCallback(
    (notifyParent = true) => {
      if (uploadDebounceTimerRef.current) {
        window.clearTimeout(uploadDebounceTimerRef.current)
        uploadDebounceTimerRef.current = null
      }
      uploadAbortControllerRef.current?.abort()
      uploadAbortControllerRef.current = null
      lastUploadedSignatureKeyRef.current = ''
      latestGeneratedNameRef.current = ''
      if (objectUrlRef.current) {
        URL.revokeObjectURL(objectUrlRef.current)
        objectUrlRef.current = ''
      }
      setSignatureBlob(null)
      setSignatureFile(null)
      setSignatureUrl('')
      if (notifyParent) {
        onSignatureChange?.({
          blob: null,
          file: null,
          url: '',
          uploadedData: null,
          uploading: false,
          uploadError: null,
        })
      }
      onFileChange?.(null)
    },
    [onSignatureChange, onFileChange],
  )

  /**
   * 根据姓名绘制签名并导出 PNG。
   */
  const generateSignatureImage = useCallback(
    (value: string) => {
      const taskId = ++generateTaskIdRef.current
      const canvas = document.createElement('canvas')
      canvas.width = SIGNATURE_WIDTH * SIGNATURE_SCALE
      canvas.height = SIGNATURE_HEIGHT * SIGNATURE_SCALE

      const context = canvas.getContext('2d')
      if (!context) return

      context.scale(SIGNATURE_SCALE, SIGNATURE_SCALE)
      context.clearRect(0, 0, canvas.width, canvas.height)
      context.fillStyle = '#232935'
      context.textAlign = 'center'
      context.textBaseline = 'alphabetic'
      context.font = `normal ${SIGNATURE_FONT_SIZE}px ${SIGNATURE_FONT_FAMILY}`
      const textMetrics = context.measureText(value)
      const ascent =
        textMetrics.actualBoundingBoxAscent || SIGNATURE_FONT_SIZE * 0.76
      const descent =
        textMetrics.actualBoundingBoxDescent || SIGNATURE_FONT_SIZE * 0.24
      const textHeight = ascent + descent
      const baselineY = (SIGNATURE_HEIGHT - textHeight) / 2 + ascent
      context.fillText(value, SIGNATURE_WIDTH / 2, baselineY)

      canvas.toBlob((blob) => {
        if (!blob || taskId !== generateTaskIdRef.current) return
        if (objectUrlRef.current) URL.revokeObjectURL(objectUrlRef.current)

        const nextUrl = URL.createObjectURL(blob)
        const nextFile = new File([blob], 'signature.png', {
          type: 'image/png',
        })
        latestGeneratedNameRef.current = value

        objectUrlRef.current = nextUrl
        setSignatureBlob(blob)
        setSignatureFile(nextFile)
        setSignatureUrl(nextUrl)
        onSignatureChange?.({
          blob,
          file: nextFile,
          url: nextUrl,
          uploadedData: null,
          uploading: false,
          uploadError: null,
        })
        onFileChange?.(nextFile)
      }, 'image/png')
    },
    [onSignatureChange, onFileChange],
  )

  /**
   * 上传生成后的签名文件：
   * - 复用项目 uploadFile 接口（FormData: file/type/uniqueId/uid）
   * - 返回数据通过 onSignatureChange / onUploadSuccess 抛给父组件
   */
  const uploadSignatureFile = useCallback(
    async (file: File, currentName: string) => {
      uploadAbortControllerRef.current?.abort()
      const abort = new AbortController()
      uploadAbortControllerRef.current = abort

      const uniqueId = `${Date.now()}${Math.floor(Math.random() * 1000000)}`
      const uid = Number(
        `${Date.now()}${Math.floor(Math.random() * 90000) + 10000}`,
      )
      const formData = new FormData()
      formData.append('file', file)
      formData.append('type', String(fileUploadType))
      formData.append('uniqueId', uniqueId)
      formData.append('uid', String(uid))

      onSignatureChange?.({
        blob: signatureBlob,
        file,
        url: signatureUrl,
        uploadedData: null,
        uploading: true,
        uploadError: null,
      })

      try {
        const res: any = await uploadFile(formData, urlToken)
        const uploadResult = { ...res, uid }
        onSignatureChange?.({
          blob: signatureBlob,
          file,
          url: signatureUrl,
          uploadedData: uploadResult,
          uploading: false,
          uploadError: null,
        })
        onUploadSuccess?.(uploadResult)
        lastUploadedSignatureKeyRef.current = `${currentName}|${file.size}`
      } catch (error) {
        if ((error as any)?.name === 'CanceledError') return
        onSignatureChange?.({
          blob: signatureBlob,
          file,
          url: signatureUrl,
          uploadedData: null,
          uploading: false,
          uploadError: error,
        })
      } finally {
        if (uploadAbortControllerRef.current === abort) {
          uploadAbortControllerRef.current = null
        }
      }
    },
    [
      fileUploadType,
      onSignatureChange,
      onUploadSuccess,
      signatureBlob,
      signatureUrl,
    ],
  )

  /**
   * 供外部 clearSignal 调用的显式清空方法。
   */
  const clearSignature = useCallback(() => {
    generateTaskIdRef.current += 1
    clearSignatureData(true)
  }, [clearSignatureData])

  /**
   * 首次挂载时加载字体。
   */
  useEffect(() => {
    ensureSignatureFontLoaded()
  }, [ensureSignatureFontLoaded])

  /**
   * 自动生成主流程：
   * - 仅在字体就绪且 enabled=true 时执行
   * - name 为空则清空
   * - name 有值则重新生成签名
   */
  useEffect(() => {
    if (!fontReady || !enabled) return
    const trimmedName = name.trim()
    if (!trimmedName) {
      generateTaskIdRef.current += 1
      clearSignatureData(true)
      return
    }
    generateSignatureImage(trimmedName)
  }, [name, fontReady, enabled, generateSignatureImage, clearSignatureData])

  /**
   * 防抖上传：
   * - 签名图生成后等待一段时间再上传，避免“每输入一个字符上传一次”
   * - 相同签名（name + file.size）不重复上传
   */
  useEffect(() => {
    if (!enabled || !signatureFile) return
    const currentName = latestGeneratedNameRef.current.trim()
    if (!currentName) return

    const signatureKey = `${currentName}|${signatureFile.size}`
    if (signatureKey === lastUploadedSignatureKeyRef.current) return

    if (uploadDebounceTimerRef.current) {
      window.clearTimeout(uploadDebounceTimerRef.current)
    }
    uploadDebounceTimerRef.current = window.setTimeout(() => {
      uploadSignatureFile(signatureFile, currentName)
    }, SIGNATURE_UPLOAD_DEBOUNCE_MS)

    return () => {
      if (uploadDebounceTimerRef.current) {
        window.clearTimeout(uploadDebounceTimerRef.current)
        uploadDebounceTimerRef.current = null
      }
    }
  }, [enabled, signatureFile, uploadSignatureFile])

  /**
   * 监听外部 clearSignal，触发组件内部清空。
   */
  useEffect(() => {
    if (clearSignal <= 0) return
    clearSignature()
  }, [clearSignal, clearSignature])

  /**
   * 组件卸载时释放 objectURL，避免内存泄漏。
   */
  useEffect(() => {
    return () => {
      if (uploadDebounceTimerRef.current) {
        window.clearTimeout(uploadDebounceTimerRef.current)
      }
      uploadAbortControllerRef.current?.abort()
