import { ChangeEvent, useRef, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { Button } from '@arco-design/web-react'
import { IconPlus } from '@arco-design/web-react/icon'
import { File_UPLOAD_TYPE } from '@common/constants/uploadTypes'
import { openapiUploadFile as uploadFile } from '@/service'

type UploadFileProps = {
  className?: string
  buttonText?: string
  accept?: string
  disabled?: boolean
  fileUploadType?: number
  onUploadSuccess?: (response: any, file: File) => void
  onUploadError?: (error: unknown, file: File) => void
  urlToken:any
}

export type UploadFileResponse = {
  id?: number
  uid?: number
  fileName?: string
  attachName?: string
  url?: string
  absUrl?: string
  [key: string]: any
}

const buildUploadFormData = (file: File, fileUploadType: number) => {
  const uniqueId = `${Date.now()}${Math.floor(Math.random() * 1000000)}`
  const uid = `${Date.now()}${Math.floor(Math.random() * 90000) + 10000}`
  const formData = new FormData()
  formData.append('file', file)
  formData.append('type', String(fileUploadType))
  formData.append('uniqueId', uniqueId)
  formData.append('uid', uid)
  return formData
}

const UploadFile = ({
  className,
  buttonText,
  accept = '*',
  disabled = false,
  fileUploadType = 1,
  onUploadSuccess,
  onUploadError,
  urlToken
}: UploadFileProps) => {
  const inputRef = useRef<HTMLInputElement | null>(null)
  const [uploading, setUploading] = useState(false)
  const { t } = useTranslation(['contractorPortal'])

  const handleOpenPicker = () => {
    if (disabled || uploading) return
    inputRef.current?.click()
  }

  const handleFileChange = async (event: ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0]
    event.target.value = ''
    if (!file) return

    setUploading(true)
    try {
      const formData = buildUploadFormData(file, fileUploadType)
      const response = await uploadFile(formData, urlToken)
      onUploadSuccess?.(response, file)
    } catch (error) {
      onUploadError?.(error, file)
    } finally {
      setUploading(false)
    }
  }

  return (
    <>
      <input
        ref={inputRef}
        type='file'
        accept={accept}
        style={{ display: 'none' }}
        onChange={handleFileChange}
      />
      <Button
        className={className}
        type='secondary'
        icon={<IconPlus />}
        disabled={disabled || uploading}
        loading={uploading}
        onClick={handleOpenPicker}
      >
        {buttonText ?? t('contractorPortal:btn.attachFile')}
      </Button>
    </>
  )
}

export default UploadFile

