      } catch (error) {
        if ((error as any)?.name === 'CanceledError') return
        onSignatureChange?.({
          blob: signatureBlob,
          file,
          url: signatureUrl,
          uploadedData: null,
          uploading: false,
          uploadError: error,
        })
      } finally {
        if (uploadAbortControllerRef.current === abort) {
          uploadAbortControllerRef.current = null
        }
      }
    },
    [
